# Generated by openai (gpt-4)
# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request
from sklearn.linear_model import LogisticRegression

app = Flask(__name__)
image_labels = {}

@app.route('/submit_label', methods=['POST'])
def submit_label():
    data = request.get_json()

    image_id = data['image_id']
    label = data['label']

    if image_id not in image_labels:
        image_labels[image_id] = []

    image_labels[image_id].append(label)

    return 'Success', 200

@app.route('/train_model', methods=['GET'])
def train_model():
    aggregated_labels = {k: max(set(v), key = v.count) for k, v in image_labels.items()}
    images = list(aggregated_labels.keys())
    labels = list(aggregated_labels.values())

    model = LogisticRegression()
    
    model.fit(images, labels)
    return 'Model trained', 200